// check(x) возвращает true для всех x >= ответа (монотонно неубывающая)
function binarySearchMinAnswer(L, R, check) {
  let lo = L, hi = R; // ищем минимальный допустимый в [L, R]
  while (lo < hi) {
    const mid = (lo + hi) >> 1;
    if (check(mid)) hi = mid;
    else lo = mid + 1;
  }
  return lo;
}

// Пример: целый sqrt(n) вниз — check(x): x*x >= n
function intSqrt(n) {
  return binarySearchMinAnswer(0, n, (x) => x * x >= n);
}

function lowerBound(arr, x) {
  let lo = 0, hi = arr.length;
  while (lo < hi) {
    const mid = (lo + hi) >> 1;
    if (arr[mid] < x) lo = mid + 1;
    else hi = mid;
  }
  return lo;
}

function upperBound(arr, x) {
  let lo = 0, hi = arr.length;
  while (lo < hi) {
    const mid = (lo + hi) >> 1;
    if (arr[mid] <= x) lo = mid + 1;
    else hi = mid;
  }
  return lo;
}

