// N-арное дерево: сколько угодно детей
class TreeNode {
  constructor(value) {
    this.value = value;
    this.children = [];
    this.parent = null; // по желанию
  }
  addChild(child) {
    child.parent = this;
    this.children.push(child);
    return child;
  }
}

// Бинарное дерево — максимум два ребёнка
class BinNode {
  constructor(value) {
    this.value = value;
    this.left = null;
    this.right = null;
  }
}

function findDFS(root, target) {
  if (!root) return null;
  if (root.value === target) return root;
  for (const ch of root.children) {
    const hit = findDFS(ch, target);
    if (hit) return hit;
  }
  return null;
}

function findBFS(root, target) {
  if (!root) return null;
  const q = [root];
  while (q.length) {
    const u = q.shift();
    if (u.value === target) return u;
    for (const ch of u.children) q.push(ch);
  }
  return null;
}

function insertUnder(parent, value) {
  const node = new TreeNode(value);
  parent.children.push(node);
  node.parent = parent;
  return node;
}

