function bfs(root, visit) {
  if (!root) return;
  const q = [root];
  while (q.length) {
    const u = q.shift();
    visit(u);
    for (const ch of u.children) q.push(ch);
  }
}

function levels(root) {
  if (!root) return [];
  const res = [];
  let q = [root];
  while (q.length) {
    const row = [];
    const next = [];
    for (const u of q) {
      row.push(u.value);
      for (const ch of u.children) next.push(ch);
    }
    res.push(row);
    q = next;
  }
  return res;
}

