function build(a, v, tl, tr, t) {
  if (tl === tr) t[v] = a[tl];
  else {
    const tm = (tl + tr) >> 1;
    build(a, v * 2, tl, tm, t);
    build(a, v * 2 + 1, tm + 1, tr, t);
    t[v] = t[v * 2] + t[v * 2 + 1];
  }
}

function sum(v, tl, tr, l, r, t) {
  if (l > r) return 0;
  if (l === tl && r === tr) return t[v];
  const tm = (tl + tr) >> 1;
  return sum(v * 2, tl, tm, l, Math.min(r, tm), t)
       + sum(v * 2 + 1, tm + 1, tr, Math.max(l, tm + 1), r, t);
}

