class Fenwick {
  constructor(n) { this.n = n; this.t = new Array(n + 1).fill(0); }
  /** delta на позиции i (1..n) */
  add(i, delta) {
    for (; i <= this.n; i += i & -i) this.t[i] += delta;
  }
  /** сумма [1..i] */
  sum(i) {
    let s = 0;
    for (; i > 0; i -= i & -i) s += this.t[i];
    return s;
  }
