const g = Array.from({ length: V }, () => []);

// ориентированное ребро u -> v
function addEdge(u, v, w = 1) {
  g[u].push({ to: v, w }); // можно хранить просто v, если вес не нужен
}

// ненаправленное: добавляем в обе стороны
function addUndirected(u, v, w = 1) {
  g[u].push({ to: v, w });
  g[v].push({ to: u, w });
}

const n = 4;
const INF = Infinity;
// dist[i][j] — вес ребра i→j или INF
const dist = Array.from({ length: n }, () => Array(n).fill(INF));
for (let i = 0; i < n; i++) dist[i][i] = 0;

function dfs(g, start, visit) {
  const seen = new Set();
  function go(v) {
    if (seen.has(v)) return;
    seen.add(v);
    visit(v);
    for (const to of g[v]) go(to);
  }
  go(start);
}

function bfs(g, start, visit) {
  const seen = new Set([start]);
  const q = [start];
  while (q.length) {
    const v = q.shift();
    visit(v);
    for (const to of g[v]) {
      if (!seen.has(to)) {
        seen.add(to);
        q.push(to);
      }
    }
  }
}

/** расстояния от start (нерешённые = -1) */
function bfsDist(g, start) {
  const n = g.length;
  const dist = new Array(n).fill(-1);
  const q = [start];
  dist[start] = 0;
  while (q.length) {
    const v = q.shift();
    for (const to of g[v]) {
      if (dist[to] === -1) {
        dist[to] = dist[v] + 1;
        q.push(to);
      }
    }
  }
  return dist;
}

