class DoublyLinkedList {
  constructor() {
    this.head = this.tail = null;
  }
  pushBack(v) {
    const n = new Node(v);
    if (!this.tail) this.head = this.tail = n;
    else {
      n.prev = this.tail;
      this.tail.next = n;
      this.tail = n;
    }
  }
  popFront() {
    if (!this.head) return undefined;
    const v = this.head.v;
    this.head = this.head.next;
    if (this.head) this.head.prev = null;
    else this.tail = null;
    return v;
  }
}

/** максимумы в каждом окне длины k */
function slidingMax(arr, k) {
  const dq = []; // индексы, значения arr[dq] убывают
  const out = [];
  for (let i = 0; i < arr.length; i++) {
    while (dq.length && arr[dq[dq.length - 1]] <= arr[i]) dq.pop();
    dq.push(i);
    while (dq[0] <= i - k) dq.shift();
    if (i >= k - 1) out.push(arr[dq[0]]);
  }
  return out;
}

