class TrieNode {
  constructor() {
    this.children = new Map();
    this.end = false;
  }
}
class Trie {
  constructor() { this.root = new TrieNode(); }
  insert(word) {
    let n = this.root;
    for (const ch of word) {
      if (!n.children.has(ch)) n.children.set(ch, new TrieNode());
      n = n.children.get(ch);
    }
    n.end = true;
  }
  has(word) {
    let n = this.root;
    for (const ch of word) {
      if (!n.children.has(ch)) return false;
      n = n.children.get(ch);
    }
    return n.end;
  }
  startsWith(prefix) {
    let n = this.root;
    for (const ch of prefix) {
      if (!n.children.has(ch)) return false;
      n = n.children.get(ch);
    }
    return true;
  }
}

