const memo = new Map();
function fibMemo(n) {
  if (n <= 1) return n;
  if (memo.has(n)) return memo.get(n);
  const v = fibMemo(n - 1) + fibMemo(n - 2);
  memo.set(n, v);
  return v;
}

function fibTab(n) {
  const dp = new Array(n + 1).fill(0);
  dp[1] = 1;
  for (let i = 2; i <= n; i++) dp[i] = dp[i - 1] + dp[i - 2];
  return dp[n];
}

function fibO1(n) {
  let a = 0, b = 1;
  for (let i = 2; i <= n; i++) [a, b] = [b, a + b];
  return n <= 1 ? n : b;
}

/** grid[i][j] === 1 — проходима, 0 — стена */
function uniquePaths(grid) {
  const n = grid.length, m = grid[0].length;
  const dp = Array.from({ length: n }, () => Array(m).fill(0));
  dp[0][0] = grid[0][0] ? 1 : 0;
  for (let i = 0; i < n; i++)
    for (let j = 0; j < m; j++) {
      if (!grid[i][j]) { dp[i][j] = 0; continue; }
      if (i === 0 && j === 0) continue;
      const up = i > 0 ? dp[i - 1][j] : 0;
      const left = j > 0 ? dp[i][j - 1] : 0;
      dp[i][j] = up + left;
    }
  return dp[n - 1][m - 1];
}

function minPathSum(cost) {
  const n = cost.length, m = cost[0].length;
  const dp = Array.from({ length: n }, () => Array(m).fill(Infinity));
  dp[0][0] = cost[0][0];
  for (let i = 0; i < n; i++)
    for (let j = 0; j < m; j++) {
      if (i === 0 && j === 0) continue;
      const up = i > 0 ? dp[i - 1][j] : Infinity;
      const le = j > 0 ? dp[i][j - 1] : Infinity;
      dp[i][j] = cost[i][j] + Math.min(up, le);
    }
  return dp[n - 1][m - 1];
}

function climbStairs(n) {
  let a = 1, b = 1;
  for (let i = 2; i <= n; i++) [a, b] = [b, a + b];
  return b;
}

function lcsLen(a, b) {
  const n = a.length, m = b.length;
  const dp = Array.from({ length: n + 1 }, () => Array(m + 1).fill(0));
  for (let i = 1; i <= n; i++)
    for (let j = 1; j <= m; j++)
      dp[i][j] =
        a[i - 1] === b[j - 1]
          ? dp[i - 1][j - 1] + 1
          : Math.max(dp[i - 1][j], dp[i][j - 1]);
  return dp[n][m];
}

