function knapsack01(weights, values, W) {
  const n = weights.length;
  const dp = Array.from({ length: n + 1 }, () => Array(W + 1).fill(0));
  for (let i = 1; i <= n; i++)
    for (let w = 0; w <= W; w++) {
      dp[i][w] = dp[i - 1][w];
      if (w >= weights[i - 1]) {
        const take = values[i - 1] + dp[i - 1][w - weights[i - 1]];
        dp[i][w] = Math.max(dp[i][w], take);
      }
    }
  return dp[n][W];
}

function knapsack01Space(weights, values, W) {
  const dp = new Array(W + 1).fill(0);
  for (let i = 0; i < weights.length; i++)
    for (let w = W; w >= weights[i]; w--)
      dp[w] = Math.max(dp[w], values[i] + dp[w - weights[i]]);
  return dp[W];
}

function unboundedKnapsack(weights, values, W) {
  const dp = new Array(W + 1).fill(0);
  for (let w = 1; w <= W; w++)
    for (let i = 0; i < weights.length; i++)
      if (w >= weights[i])
        dp[w] = Math.max(dp[w], values[i] + dp[w - weights[i]]);
  return dp[W];
}

/** число способов набрать сумму S монетами (порядок не важен), бесконечные монеты */
function coinChangeCombinations(coins, S) {
  const dp = new Array(S + 1).fill(0);
  dp[0] = 1;
  for (const c of coins)
    for (let s = c; s <= S; s++) dp[s] += dp[s - c];
  return dp[S];
}

