function treeIndependentSet(g, root, weight) {
  function dfs(v, parent) {
    let take = weight[v], skip = 0;
    for (const to of g[v]) {
      if (to === parent) continue;
      const [t, s] = dfs(to, v);
      take += s;
      skip += Math.max(t, s);
    }
    return [take, skip];
  }
  const [take, skip] = dfs(root, -1);
  return Math.max(take, skip);
}

/** order — топологический порядок вершин */
function longestPathDAG(g, order, n) {
  const dp = Array(n).fill(0);
  for (const v of order)
    for (const to of g[v]) dp[to] = Math.max(dp[to], dp[v] + 1);
  return Math.max(...dp);
}

function pathCountDAG(g, order, s) {
  const n = g.length;
  const dp = new Array(n).fill(0);
  dp[s] = 1;
  for (const u of order)
    for (const v of g[u]) dp[v] += dp[u];
  return dp;
}

