function prefixFunction(s) {
  const pi = new Array(s.length).fill(0);
  for (let i = 1; i < s.length; i++) {
    let j = pi[i - 1];
    while (j > 0 && s[i] !== s[j]) j = pi[j - 1];
    if (s[i] === s[j]) j++;
    pi[i] = j;
  }
  return pi;
}

function kmpSearch(text, pat) {
  const pi = prefixFunction(pat);
  const res = [];
  let j = 0;
  for (let i = 0; i < text.length; i++) {
    while (j > 0 && text[i] !== pat[j]) j = pi[j - 1];
    if (text[i] === pat[j]) j++;
    if (j === pat.length) {
      res.push(i - pat.length + 1);
      j = pi[j - 1];
    }
  }
  return res;
}

function zFunction(s) {
  const n = s.length;
  const z = new Array(n).fill(0);
  let l = 0, r = 0;
  for (let i = 1; i < n; i++) {
    if (i <= r) z[i] = Math.min(r - i + 1, z[i - l]);
    while (i + z[i] < n && s[z[i]] === s[i + z[i]]) z[i]++;
    if (i + z[i] - 1 > r) { l = i; r = i + z[i] - 1; }
  }
  return z;
}

function rabinKarp(text, pat, p = 1e9 + 7, b = 911382323) {
  const n = text.length, m = pat.length;
  if (m > n) return [];
  let h = 0, hp = 0, pw = 1;
  for (let i = 0; i < m; i++) {
    h = (h * b + text.charCodeAt(i)) % p;
    hp = (hp * b + pat.charCodeAt(i)) % p;
    if (i) pw = (pw * b) % p;
  }
  const out = [];
  for (let i = 0; i <= n - m; i++) {
    if (h === hp && text.slice(i, i + m) === pat) out.push(i);
    if (i < n - m) {
      h = (h - text.charCodeAt(i) * pw % p + p) % p;
      h = (h * b + text.charCodeAt(i + m)) % p;
    }
  }
  return out;
}

