/** capacities[u][v], нет ребра = 0 */
function edmondsKarp(cap, s, t) {
  const n = cap.length;
  const flow = Array.from({ length: n }, () => Array(n).fill(0));
  let total = 0;
  for (;;) {
    const parent = new Array(n).fill(-1);
    const q = [s];
    parent[s] = s;
    for (let qi = 0; qi < q.length; qi++) {
      const u = q[qi];
      for (let v = 0; v < n; v++) {
        if (parent[v] !== -1) continue;
        const rem = cap[u][v] - flow[u][v];
        if (rem <= 0) continue;
        parent[v] = u;
        q.push(v);
      }
    }
    if (parent[t] === -1) break;
    let add = Infinity;
    for (let v = t; v !== s; v = parent[v]) {
      const u = parent[v];
      add = Math.min(add, cap[u][v] - flow[u][v]);
    }
    for (let v = t; v !== s; v = parent[v]) {
      const u = parent[v];
      flow[u][v] += add;
      flow[v][u] -= add;
    }
    total += add;
  }
  return total;
}

